export function validatePortfolioData(rows){const messages=[]; if(!rows?.length) return {isValid:false,messages:[{type:'error',text:'The uploaded file is empty.'}],cleaned:[]}; const required=['stock','sector','return']; const keys=Object.keys(rows[0]).map(k=>k.trim().toLowerCase()); const missing=required.filter(k=>!keys.includes(k)); if(missing.length) return {isValid:false,messages:[{type:'error',text:`Missing required columns: ${missing.join(', ')}`}],cleaned:[]}; const cleaned=rows.map(r=>({stock:String(r.stock??'').trim(),sector:String(r.sector??'').trim(),return:Number(r.return)})); if(cleaned.some(r=>Number.isNaN(r.return))) messages.push({type:'warning',text:'Some return values were invalid and were ignored.'}); const validRows=cleaned.filter(r=>r.stock&&r.sector&&!Number.isNaN(r.return)); messages.push({type:'success',text:'Portfolio file validated successfully.'}); return {isValid:validRows.length>0,messages,cleaned:validRows}; } export function calculateMetrics(rows){const avg_return=rows.reduce((a,b)=>a+b.return,0)/rows.length; const total_return=rows.reduce((a,b)=>a+b.return,0); const top=[...rows].sort((a,b)=>b.return-a.return)[0]; const worst=[...rows].sort((a,b)=>a.return-b.return)[0]; return {avg_return,total_return,top_stock:top.stock,top_return:top.return,worst_stock:worst.stock,worst_return:worst.return};} export function calculateRiskMetrics(rows,riskFreeRate=0.02){const returns=rows.map(r=>r.return/100); const avg=returns.reduce((a,b)=>a+b,0)/returns.length; const variance=returns.reduce((a,b)=>a+((b-avg)**2),0)/returns.length; const vol=Math.sqrt(variance); return {volatility:vol*100,sharpe_ratio:vol?(avg-riskFreeRate)/vol:0};} export function calculateAllocation(rows){const map={}; rows.forEach(r=>map[r.sector]=(map[r.sector]||0)+1); return Object.entries(map).map(([name,count])=>({name,value:Number(((count/rows.length)*100).toFixed(2))}));} export function sectorPerformance(rows){const groups={}; rows.forEach(r=>{groups[r.sector] ||= []; groups[r.sector].push(r.return)}); return Object.entries(groups).map(([name,vals])=>({name,value:Number((vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(2))}));} export function topHoldings(rows){return [...rows].sort((a,b)=>b.return-a.return).slice(0,5);}